using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable and
            // direct SQL queries referencing c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityName|<key>" to just "<key>".
            // Use IdProperty() with a value-generated shadow property to keep the
            // "Product|<Id>" format that existing documents use.
            entity.Property<string>("__id");
            entity.HasKey("__id");

            // HasIndex is not supported by the Cosmos DB provider; removed.
        });
    }

    public override int SaveChanges() => SaveChangesAsync().GetAwaiter().GetResult();
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = string.Empty;
}

