using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Pin the old name so existing documents and direct SQL
            // queries (c.Discriminator) keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — id value format changed.
            // EF Core 8 wrote id as "Product|<key>"; EF Core 9 writes
            // just "<key>".  Map the explicit id property so reads/writes
            // against existing documents use the old format.
            entity.HasKey(nameof(Product.CosmosId));
            entity.Property(p => p.CosmosId).ToJsonProperty("id");
            entity.Property(p => p.Id).ToJsonProperty("Id");

            // HasIndex is not supported by the Cosmos provider; removed.
        });
    }
}

class Product
{
    /// <summary>
    /// Cosmos document id — preserves the EF Core 8 "Product|{key}" format.
    /// </summary>
    public string CosmosId
    {
        get => $"Product|{Id}";
        private set { /* EF Core materializer */ }
    }

    public int Id { get; set; }
    public string Sku { get; set; } = string.Empty;
}

